1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: string; items: Item[] };
14	type Input = { steps: Step[] };
15	
16	const COMPONENT_TYPES = new Set(["rune"]);
17	const BLOCK_BASE_PREMIUM = 60;
18	const BLOCK_SIZE = 3;
19	
20	const withFirstInsurance = (base: number): number =>
21	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
22	
23	const itemsSubtotal = (items: Item[]): number => {
24	  const componentsByType = new Map<string, Item[]>();
25	  let total = 0;
26	  for (const item of items) {
27	    if (COMPONENT_TYPES.has(item.type)) {
28	      const group = componentsByType.get(item.type) ?? [];
29	      group.push(item);
30	      componentsByType.set(item.type, group);
31	    } else {
32	      total += withFirstInsurance(BASE_PREMIUMS[item.type] ?? 0);
33	    }
34	  }
35	  for (const group of componentsByType.values()) {
36	    if (group.length === BLOCK_SIZE) {
37	      total += withFirstInsurance(BLOCK_BASE_PREMIUM);
38	    } else {
39	      total += group.reduce(
40	        (sum, item) => sum + withFirstInsurance(BASE_PREMIUMS[item.type] ?? 0),
41	        0,
42	      );
43	    }
44	  }
45	  return total;
46	};
47	
48	const quotePremium = (step: Step): number => {
49	  return Math.ceil(itemsSubtotal(step.items)) + PROCESSING_FEE;
50	};
51	
52	export const runScenario = (input: unknown): unknown => {
53	  const { steps } = input as Input;
54	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
55	  return { results };
56	};
